-- ============================================================================
-- ARCTOS Seed: ISO/IEC 27701:2019 — Privacy Information Management (PIMS)
-- Source: ISO/IEC 27701:2019 (Extension to ISO/IEC 27001 and ISO/IEC 27002
--         for privacy information management — Requirements and guidelines)
--
-- Structure:
--   Clauses 5–8 = PIMS-specific extensions to 27001 management-system clauses
--   Annex A     = PIMS-specific controls for PII Controllers (32 controls)
--   Annex B     = PIMS-specific controls for PII Processors (18 controls)
--
-- Target modules: dpms, isms
-- ============================================================================

INSERT INTO catalog (id, name, description, catalog_type, scope, source, version, language, is_active, target_modules)
VALUES (
  'c0000000-0000-0000-0000-277010000001',
  'ISO/IEC 27701:2019 PIMS',
  'Privacy Information Management System extension to ISO 27001/27002. Includes management-system extensions and 50 privacy controls (32 controller, 18 processor).',
  'control', 'platform', 'iso_27701_2019', '2019', 'en', true, '{dpms,isms}'
) ON CONFLICT (id) DO NOTHING;

INSERT INTO catalog_entry (catalog_id, code, name, name_de, description, description_de, level, sort_order, status) VALUES
-- ── Clause extensions to ISO 27001 ─────────────────────────────────────────
('c0000000-0000-0000-0000-277010000001', '5', 'PIMS-specific requirements (extending ISO 27001)', 'PIMS-spezifische Anforderungen (Erweiterung ISO 27001)', 'Extensions to ISO 27001 management-system clauses for privacy information management', 'Erweiterungen der ISO 27001-Klauseln für ein Datenschutzinformations-Managementsystem', 0, 100, 'active'),
('c0000000-0000-0000-0000-277010000001', '5.2.1', 'Understanding the organization and its context (PII)', 'Verständnis der Organisation und ihres Kontextes (PII)', 'The organization shall determine its role as PII controller, joint controller and/or PII processor.', 'Die Organisation muss ihre Rolle als PII-Controller, Joint-Controller und/oder PII-Processor bestimmen.', 1, 110, 'active'),
('c0000000-0000-0000-0000-277010000001', '5.2.2', 'Understanding interested parties'' needs and expectations', 'Verständnis der Bedürfnisse interessierter Parteien', 'Identify needs of PII principals, regulators, customers and partners regarding privacy.', 'Bedürfnisse von Betroffenen, Regulierungsbehörden, Kunden und Partnern bzgl. Datenschutz identifizieren.', 1, 120, 'active'),
('c0000000-0000-0000-0000-277010000001', '5.2.3', 'Determining the scope of the PIMS', 'Geltungsbereich des PIMS festlegen', 'Define the scope of the PIMS considering all PII processing activities.', 'PIMS-Geltungsbereich unter Berücksichtigung aller PII-Verarbeitungstätigkeiten festlegen.', 1, 130, 'active'),
('c0000000-0000-0000-0000-277010000001', '5.4.1.2', 'Information security risk assessment (PII)', 'IS-Risikobewertung (PII)', 'Risk assessment shall include impact on privacy of PII principals.', 'Die Risikobewertung muss die Auswirkungen auf den Datenschutz der Betroffenen einschließen.', 1, 140, 'active'),
('c0000000-0000-0000-0000-277010000001', '5.4.1.3', 'Information security risk treatment (PII)', 'IS-Risikobehandlung (PII)', 'Risk treatment shall include controls from Annex A (controller) or Annex B (processor) as applicable.', 'Die Risikobehandlung muss anwendbare Controls aus Annex A (Controller) oder Annex B (Processor) einschließen.', 1, 150, 'active'),

-- ── Annex A: PIMS-specific Controls for Controllers (32) ───────────────────
('c0000000-0000-0000-0000-277010000001', 'A.7', 'Annex A — PII Controller Specific Controls', 'Annex A — PII-Controller-spezifische Controls', 'Privacy controls applicable to PII controllers', 'Datenschutz-Controls für PII-Controller', 0, 200, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.2.1', 'Identify and document purpose', 'Zweck identifizieren und dokumentieren', 'The organization shall identify and document the specific purposes for which PII will be processed.', 'Die Organisation muss die spezifischen Zwecke der PII-Verarbeitung identifizieren und dokumentieren.', 1, 210, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.2.2', 'Identify lawful basis', 'Rechtsgrundlage identifizieren', 'The organization shall identify, document and comply with the lawful basis for processing PII.', 'Die Organisation muss die Rechtsgrundlage für die PII-Verarbeitung identifizieren, dokumentieren und einhalten.', 1, 220, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.2.3', 'Determine when and how consent is to be obtained', 'Festlegen wann und wie Einwilligung einzuholen ist', 'The organization shall determine and document the procedure to obtain consent.', 'Die Organisation muss das Verfahren zur Einwilligungseinholung festlegen und dokumentieren.', 1, 230, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.2.4', 'Obtain and record consent', 'Einwilligung einholen und dokumentieren', 'Where consent is the lawful basis, the organization shall obtain and record consent from PII principals.', 'Wo Einwilligung Rechtsgrundlage ist, muss die Organisation die Einwilligung einholen und dokumentieren.', 1, 240, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.2.5', 'Privacy impact assessment', 'Datenschutz-Folgenabschätzung', 'The organization shall assess the need for and conduct a privacy impact assessment (DPIA).', 'Die Organisation muss den Bedarf einer Datenschutz-Folgenabschätzung (DPIA) prüfen und durchführen.', 1, 250, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.2.6', 'Contracts with PII processors', 'Verträge mit PII-Verarbeitern', 'The organization shall have written contracts with each PII processor that processes PII on its behalf.', 'Die Organisation muss schriftliche Verträge mit jedem PII-Verarbeiter haben.', 1, 260, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.2.7', 'Joint PII controller', 'Gemeinsame PII-Controller', 'The organization shall determine respective roles and responsibilities of joint PII controllers in a transparent manner.', 'Die Organisation muss die Rollen und Verantwortlichkeiten gemeinsamer PII-Controller transparent festlegen.', 1, 270, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.2.8', 'Records related to processing PII', 'Aufzeichnungen zur PII-Verarbeitung', 'The organization shall maintain records of PII processing (similar to Article 30 GDPR ROPA).', 'Die Organisation muss Aufzeichnungen über PII-Verarbeitungstätigkeiten führen (vgl. Art. 30 DSGVO).', 1, 280, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.1', 'Determining and fulfilling obligations to PII principals', 'Pflichten gegenüber Betroffenen festlegen und erfüllen', 'The organization shall determine and document obligations toward PII principals and procedures for fulfilling them.', 'Die Organisation muss die Pflichten gegenüber Betroffenen und Verfahren zu deren Erfüllung festlegen.', 1, 310, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.2', 'Determining information for PII principals', 'Informationen für Betroffene festlegen', 'The organization shall determine and provide information to PII principals.', 'Die Organisation muss Informationen für Betroffene festlegen und bereitstellen.', 1, 320, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.3', 'Providing information to PII principals', 'Information an Betroffene erteilen', 'The organization shall provide PII principals with information regarding the processing of their PII in a clear and easily accessible form.', 'Die Organisation muss Betroffenen Informationen zur PII-Verarbeitung in klarer und leicht zugänglicher Form bereitstellen.', 1, 330, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.4', 'Providing mechanism to modify or withdraw consent', 'Mechanismus zur Änderung oder Widerruf der Einwilligung', 'The organization shall provide PII principals with a mechanism to modify or withdraw their consent.', 'Die Organisation muss Betroffenen einen Mechanismus zur Änderung oder zum Widerruf der Einwilligung bereitstellen.', 1, 340, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.5', 'Providing mechanism to object to PII processing', 'Mechanismus zum Widerspruch gegen PII-Verarbeitung', 'The organization shall provide PII principals with a mechanism to object to processing of their PII.', 'Die Organisation muss Betroffenen einen Mechanismus zum Widerspruch gegen die PII-Verarbeitung bereitstellen.', 1, 350, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.6', 'Access, correction and/or erasure', 'Zugang, Berichtigung und/oder Löschung', 'The organization shall provide mechanism to provide PII access, correction and erasure (DSR fulfilment).', 'Die Organisation muss Mechanismen für PII-Zugang, -Berichtigung und -Löschung bereitstellen (DSR-Erfüllung).', 1, 360, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.7', 'PII controllers'' obligations to inform third parties', 'Informationspflichten gegenüber Dritten', 'The organization shall inform third parties to whom PII has been disclosed of any modification, withdrawal or objections.', 'Die Organisation muss Dritte, denen PII offengelegt wurde, über Änderungen, Widerruf oder Widersprüche informieren.', 1, 370, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.8', 'Providing copy of PII processed', 'Bereitstellung Kopie der verarbeiteten PII', 'The organization shall be able to provide a copy of the PII that is processed (data portability).', 'Die Organisation muss in der Lage sein, eine Kopie der verarbeiteten PII bereitzustellen (Datenportabilität).', 1, 380, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.9', 'Handling requests', 'Bearbeitung von Anfragen', 'The organization shall define and document policies and procedures for handling requests from PII principals.', 'Die Organisation muss Richtlinien und Verfahren zur Bearbeitung von Anfragen Betroffener festlegen.', 1, 390, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.3.10', 'Automated decision making', 'Automatisierte Entscheidungsfindung', 'The organization shall identify and address obligations relating to decisions based solely on automated processing.', 'Die Organisation muss Pflichten in Bezug auf ausschließlich automatisierte Entscheidungen identifizieren und adressieren.', 1, 400, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.1', 'Limit collection', 'Erhebung begrenzen', 'The organization shall limit the collection of PII to the minimum that is relevant, proportional and necessary for the identified purposes.', 'Die Organisation muss die PII-Erhebung auf das relevante, verhältnismäßige und notwendige Minimum begrenzen.', 1, 410, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.2', 'Limit processing', 'Verarbeitung begrenzen', 'The organization shall limit the processing of PII to that which is necessary for the identified purposes.', 'Die Organisation muss die PII-Verarbeitung auf das für die Zwecke Notwendige begrenzen.', 1, 420, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.3', 'Accuracy and quality', 'Richtigkeit und Qualität', 'The organization shall ensure and document that PII is as accurate, complete and up-to-date as is necessary.', 'Die Organisation muss sicherstellen und dokumentieren, dass PII so korrekt, vollständig und aktuell wie nötig ist.', 1, 430, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.4', 'PII minimization objectives', 'Datenminimierungsziele', 'The organization shall define and document data-minimization objectives and the techniques used.', 'Die Organisation muss Datenminimierungsziele und -techniken festlegen und dokumentieren.', 1, 440, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.5', 'PII de-identification and deletion at the end of processing', 'De-Identifikation und Löschung am Ende der Verarbeitung', 'The organization shall delete or de-identify PII as soon as the original purpose has expired.', 'Die Organisation muss PII löschen oder de-identifizieren, sobald der ursprüngliche Zweck entfällt.', 1, 450, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.6', 'Temporary files', 'Temporäre Dateien', 'The organization shall ensure that temporary files containing PII are disposed of (e.g., erased or destroyed) within a defined period.', 'Die Organisation muss sicherstellen, dass temporäre Dateien mit PII innerhalb eines definierten Zeitraums entsorgt werden.', 1, 460, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.7', 'Retention', 'Aufbewahrung', 'The organization shall not retain PII for longer than is necessary for the purposes for which it is processed.', 'Die Organisation darf PII nicht länger aufbewahren als für die Verarbeitungszwecke notwendig.', 1, 470, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.8', 'Disposal', 'Entsorgung', 'The organization shall have policies, procedures and/or mechanisms in place for the disposal of PII.', 'Die Organisation muss Richtlinien, Verfahren und/oder Mechanismen zur PII-Entsorgung haben.', 1, 480, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.4.9', 'PII transmission controls', 'Maßnahmen zur PII-Übertragung', 'The organization shall ensure that PII transmitted is subject to appropriate controls to ensure that the data reaches its destination.', 'Die Organisation muss sicherstellen, dass übertragene PII angemessenen Maßnahmen unterliegt, damit sie ihr Ziel erreicht.', 1, 490, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.5.1', 'Identify basis for PII transfer between jurisdictions', 'Grundlage für PII-Transfer zwischen Jurisdiktionen identifizieren', 'The organization shall identify and document the relevant basis for transfers of PII between jurisdictions.', 'Die Organisation muss die relevante Grundlage für PII-Transfers zwischen Jurisdiktionen identifizieren und dokumentieren.', 1, 510, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.5.2', 'Countries and international organizations to which PII can be transferred', 'Länder und internationale Organisationen für PII-Transfer', 'The organization shall specify and document the countries and international organizations to which PII can possibly be transferred.', 'Die Organisation muss die Länder und internationalen Organisationen, in die PII übertragen werden können, spezifizieren und dokumentieren.', 1, 520, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.5.3', 'Records of transfers of PII', 'Aufzeichnungen über PII-Transfers', 'The organization shall record transfers of PII to or from third parties and ensure cooperation with those parties to support future requests.', 'Die Organisation muss PII-Transfers von/zu Dritten aufzeichnen und mit diesen Parteien für zukünftige Anfragen zusammenarbeiten.', 1, 530, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.7.5.4', 'Records of PII disclosure to third parties', 'Aufzeichnungen über PII-Offenlegung an Dritte', 'The organization shall record disclosures of PII to third parties, including what PII has been disclosed, to whom and when.', 'Die Organisation muss Offenlegungen von PII an Dritte aufzeichnen, inkl. welche PII, an wen und wann.', 1, 540, 'active'),

-- ── Annex B: PIMS-specific Controls for Processors (18) ────────────────────
('c0000000-0000-0000-0000-277010000001', 'A.8', 'Annex B — PII Processor Specific Controls', 'Annex B — PII-Processor-spezifische Controls', 'Privacy controls applicable to PII processors', 'Datenschutz-Controls für PII-Verarbeiter', 0, 600, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.2.1', 'Customer agreement', 'Kundenvereinbarung', 'The organization shall ensure that there is a written contract that is binding upon both parties.', 'Die Organisation muss sicherstellen, dass ein für beide Parteien bindender schriftlicher Vertrag besteht.', 1, 610, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.2.2', 'Organization''s purposes', 'Zwecke der Organisation', 'The organization shall ensure PII processed on behalf of a customer is only processed for the purposes expressed in the documented instructions.', 'Die Organisation muss sicherstellen, dass auftragsweise verarbeitete PII nur für die in den Weisungen festgelegten Zwecke verarbeitet wird.', 1, 620, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.2.3', 'Marketing and advertising use', 'Marketing- und Werbenutzung', 'The organization shall not use PII processed under a contract for the purposes of marketing and advertising without consent.', 'Die Organisation darf vertraglich verarbeitete PII nicht ohne Einwilligung für Marketing und Werbung nutzen.', 1, 630, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.2.4', 'Infringing instruction', 'Rechtswidrige Weisung', 'The organization shall inform the customer if instructions infringe applicable legislation.', 'Die Organisation muss den Kunden informieren, wenn Weisungen gegen anwendbares Recht verstoßen.', 1, 640, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.2.5', 'Customer obligations', 'Kundenpflichten', 'The organization shall provide the customer with appropriate information and records to enable their compliance with PII obligations.', 'Die Organisation muss dem Kunden Informationen und Aufzeichnungen für die Erfüllung seiner PII-Pflichten bereitstellen.', 1, 650, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.3.1', 'Obligations to PII principals', 'Pflichten gegenüber Betroffenen', 'The organization shall provide the customer with the means to comply with its obligations related to PII principals.', 'Die Organisation muss dem Kunden Mittel zur Erfüllung seiner Pflichten gegenüber Betroffenen bereitstellen.', 1, 710, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.4.1', 'Temporary files', 'Temporäre Dateien', 'The organization shall ensure that temporary files containing PII are disposed of within a defined period.', 'Die Organisation muss sicherstellen, dass temporäre PII-Dateien innerhalb eines definierten Zeitraums entsorgt werden.', 1, 810, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.4.2', 'Return, transfer or disposal of PII', 'Rückgabe, Transfer oder Entsorgung von PII', 'The organization shall provide the ability to return, transfer and/or disposal of PII in a secure manner.', 'Die Organisation muss die Möglichkeit zur sicheren Rückgabe, Übertragung und/oder Entsorgung von PII bereitstellen.', 1, 820, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.4.3', 'PII transmission controls', 'PII-Übertragungsmaßnahmen', 'The organization shall subject PII transmitted over a data-transmission network to appropriate controls.', 'Die Organisation muss über Netzwerke übertragene PII angemessenen Maßnahmen unterwerfen.', 1, 830, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.5.1', 'Basis for PII transfer between jurisdictions', 'Grundlage für PII-Transfer zwischen Jurisdiktionen', 'The organization shall inform the customer in a timely manner of the basis for transfers of PII between jurisdictions.', 'Die Organisation muss den Kunden zeitnah über die Grundlage für PII-Transfers zwischen Jurisdiktionen informieren.', 1, 910, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.5.2', 'Countries and international organizations to which PII can be transferred', 'Länder/Organisationen für PII-Transfer', 'The organization shall specify and document countries and international organizations to which PII can possibly be transferred on the customer''s behalf.', 'Die Organisation muss Länder und internationale Organisationen für mögliche PII-Transfers im Auftrag des Kunden spezifizieren und dokumentieren.', 1, 920, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.5.3', 'Records of PII disclosure to third parties', 'Aufzeichnungen PII-Offenlegung an Dritte', 'The organization shall record disclosures of PII to third parties.', 'Die Organisation muss Offenlegungen von PII an Dritte aufzeichnen.', 1, 930, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.5.4', 'Notification of PII disclosure requests', 'Meldung PII-Offenlegungsanfragen', 'The organization shall notify the customer of any legally binding requests for disclosure of PII.', 'Die Organisation muss den Kunden über rechtsverbindliche PII-Offenlegungsanfragen informieren.', 1, 940, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.5.5', 'Legally binding PII disclosures', 'Rechtsverbindliche PII-Offenlegungen', 'The organization shall reject any requests for PII disclosure not legally binding, consult with the customer, and accept contractually agreed requests.', 'Die Organisation muss nicht-rechtsverbindliche PII-Offenlegungsanfragen ablehnen, mit dem Kunden konsultieren und vertraglich vereinbarte Anfragen akzeptieren.', 1, 950, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.5.6', 'Disclosure of subcontractors used to process PII', 'Offenlegung Unterauftragsverarbeiter', 'The organization shall disclose any use of subcontractors to process PII to the customer in due time.', 'Die Organisation muss den Einsatz von Unterauftragsverarbeitern für PII zeitnah dem Kunden offenlegen.', 1, 960, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.5.7', 'Engagement of a subcontractor to process PII', 'Beauftragung eines Unterauftragsverarbeiters', 'The organization shall only engage subcontractors to process PII according to the customer contract.', 'Die Organisation darf Unterauftragsverarbeiter für PII nur entsprechend dem Kundenvertrag einsetzen.', 1, 970, 'active'),
('c0000000-0000-0000-0000-277010000001', 'A.8.5.8', 'Change of subcontractor to process PII', 'Wechsel eines PII-Unterauftragsverarbeiters', 'The organization shall, in the case of any intended changes concerning the addition or replacement of subcontractors, inform the customer in due time.', 'Die Organisation muss den Kunden bei beabsichtigten Änderungen (Hinzufügen/Austausch) von Unterauftragsverarbeitern zeitnah informieren.', 1, 980, 'active')
ON CONFLICT (catalog_id, code) DO NOTHING;

